const SUPABASE_URL = 'https://byoriebhtbysanjhimlu.supabase.co';
const SUPABASE_KEY = 'REPLACE_WITH_SUPABASE_SERVICE_ROLE_KEY';
const headers = { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` };
const contentId = $input.first().json.content_id;
const contentResp = await fetch(`${SUPABASE_URL}/rest/v1/social_content_queue?id=eq.${contentId}&select=*`, { headers });
const content = await contentResp.json();
if (!content || content.length === 0) throw new Error('Content not found: ' + contentId);
const row = content[0];
const configResp = await fetch(`${SUPABASE_URL}/rest/v1/social_content_config?platform=eq.${row.platform}&select=*`, { headers });
const config = await configResp.json();
const merged = { ...row, credentials: config[0]?.credentials || {}, settings: config[0]?.settings || {} };
return [{ json: merged }];

const item = $input.first().json;
const credentials = typeof item.credentials === 'string' ? JSON.parse(item.credentials) : (item.credentials || {});
const settings = typeof item.settings === 'string' ? JSON.parse(item.settings) : (item.settings || {});

const accessToken = credentials.access_token;
const authorUrn = settings.author_urn || credentials.person_urn;

if (!accessToken || !authorUrn) {
  throw new Error('LinkedIn credentials not configured. Connect LinkedIn in Admin > Social Content.');
}

// Build the full post text with hashtags
let fullText = item.post_text || '';
if (item.cta_text) fullText += '\n\n' + item.cta_text;
if (item.cta_url) fullText += '\n' + item.cta_url;
const hashtags = typeof item.hashtags === 'string' ? JSON.parse(item.hashtags || '[]') : (item.hashtags || []);
if (hashtags.length > 0) {
  fullText += '\n\n' + hashtags.map(h => h.startsWith('#') ? h : '#' + h).join(' ');
}

return [{ json: {
  content_id: item.id,
  access_token: accessToken,
  author_urn: authorUrn,
  full_text: fullText,
  image_url: item.image_url,
  has_image: !!item.image_url
} }];

const SUPABASE_URL = 'https://byoriebhtbysanjhimlu.supabase.co';
const SUPABASE_KEY = 'REPLACE_WITH_SUPABASE_SERVICE_ROLE_KEY';
const contentId = $node['Prepare LinkedIn Post'].json.content_id;
const platformPostId = $input.first().json.id || '';
const resp = await fetch(`${SUPABASE_URL}/rest/v1/social_content_queue?id=eq.${contentId}`, {
  method: 'PATCH',
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
  body: JSON.stringify({ status: 'published', published_at: new Date().toISOString(), platform_post_id: platformPostId })
});
const result = await resp.json();
return [{ json: Array.isArray(result) ? result[0] : result }];

